Hi @aravindmurali22,

I looked at LiteRT code and there is no mentioning of TOSA dialect at all. I believe this issue is with the tensorflow repo itself.

@sjarus

> [@weifengpy](https://github.com/weifengpy) can you comment on this, should we close as wont-fix for FSDP1 as long as we confirm working for fully_shard?

the solution is the same across FSDP1 and FSDP2 (fully_shard). full script to set ignored params in FSDP2

```
"""
Repro for https://github.com/pytorch/pytorch/issues/177017
fully_shard (FSDP2) + nn.utils.parametrize + DDP for ignored params.

Run with: torchrun --nproc_per_node=2 repro_177017_fsdp2.py
"""
import os
import torch
import torch.nn as nn


class SubModule(nn.Module):
    def __init__(self):
        super().__init__()
        self.my_param = nn.Parameter(torch.randn(1024, 1024))

    def forward(self, x):
        return x @ self.my_param


class TransformerBlock(nn.Module):
    def __init__(self):
        super().__init__()
        self.sub = SubModule()
        self.linear = nn.Linear(1024, 1024)

    def forward(self, x):
        return self.linear(self.sub(x))


class Model(nn.Module):
    def __init__(self, num_layers=4):
        super().__init__()
        self.layers = nn.ModuleList([TransformerBlock() for _ in range(num_layers)])

    def forward(self, x):
        for layer in self.layers:
            x = layer(x)
        return x


class IdentityParametrization(nn.Module):
    def forward(self, x):
        return x


def patch_forward(original_forward):
    def patched_forward(self, x):
        nn.utils.parametrize.register_parametrization(
            self, "my_param", IdentityParametrization()
        )
        result = x @ self.my_param
        nn.utils.parametrize.remove_parametrizations(
            self, "my_param", leave_parametrized=False
        )
        return result

    SubModule.forward = patched_forward


def main():
    use_dist = "WORLD_SIZE" in os.environ
    if use_dist:
        import torch.distributed as dist
        from torch.distributed._composable.fsdp import fully_shard

        dist.init_process_group("nccl")
        rank = dist.get_rank()
        torch.cuda.set_device(rank)
        device = f"cuda:{rank}"
    else:
        device = "cuda:0"

    model = Model().to(device)

    if use_dist:
        # Apply fully_shard per TransformerBlock, ignoring my_param
        for layer in model.layers:
            fully_shard(layer, ignored_params={layer.sub.my_param})
        fully_shard(model)

        # Wrap with DDP to all-reduce gradients for the FSDP-ignored my_param.
        ddp_params_to_ignore = []
        for name, param in model.named_parameters():
            if "my_param" not in name:
                ddp_params_to_ignore.append(name)
        torch.nn.parallel.DistributedDataParallel._set_params_and_buffers_to_ignore_for_model(
            model, ddp_params_to_ignore
        )
        model = torch.nn.parallel.DistributedDataParallel(model, device_ids=[rank])

    x = torch.randn(2, 1024, device=device)
    # First forward pass (before patching)
    model(x)

    # Monkey-patch SubModule.forward to register/remove parametrizations dynamically
    original_forward = SubModule.forward
    patch_forward(original_forward)

    # Second forward pass (after patching)
    out = model(x)
    out.sum().backward()

    base = model
    while hasattr(base, 'module'):
        base = base.module
    for i, layer in enumerate(base.layers):
        grad = layer.sub.my_param.grad
        print(f"layer {i} my_param.grad: {grad is not None} (shape={grad.shape if grad is not None else None})")

    print("passes")

    if use_dist:
        dist.destroy_process_group()


if __name__ == "__main__":
    main()
```

`fully_shard` works without any workaround, `ignored_params` not needed.

`torchrun --nproc_per_node=2 <filename>.py`

```
import os
import torch
import torch.nn as nn
import torch.distributed as dist
from torch.distributed.fsdp import fully_shard


class SubModule(nn.Module):
    def __init__(self):
        super().__init__()
        self.my_param = nn.Parameter(torch.randn(1024, 1024))

    def forward(self, x):
        return x @ self.my_param


class TransformerBlock(nn.Module):
    def __init__(self):
        super().__init__()
        self.sub = SubModule()
        self.linear = nn.Linear(1024, 1024)

    def forward(self, x):
        return self.linear(self.sub(x))


class Model(nn.Module):
    def __init__(self, num_layers=4):
        super().__init__()
        self.layers = nn.ModuleList([TransformerBlock() for _ in range(num_layers)])

    def forward(self, x):
        for layer in self.layers:
            x = layer(x)
        return x


class IdentityParametrization(nn.Module):
    def forward(self, x):
        return x


def patch_forward(original_forward):
    def patched_forward(self, x):
        nn.utils.parametrize.register_parametrization(
            self, "my_param", IdentityParametrization()
        )
        result = x @ self.my_param
        nn.utils.parametrize.remove_parametrizations(
            self, "my_param", leave_parametrized=False
        )
        return result

    SubModule.forward = patched_forward


def main():
    dist.init_process_group("nccl")
    rank = dist.get_rank()
    torch.cuda.set_device(rank)
    device = f"cuda:{rank}"

    model = Model().to(device)

    for layer in model.layers:
        fully_shard(layer)
    fully_shard(model)

    x = torch.randn(2, 1024, device=device)
    model(x)

    original_forward = SubModule.forward
    patch_forward(original_forward)

    out = model(x)
    out.sum().backward()

    for i, layer in enumerate(model.layers):
        grad = layer.sub.my_param.grad
        print(f"layer {i} my_param.grad: {grad is not None} (shape={grad.shape if grad is not None else None})")

    print("passes")
    dist.destroy_process_group()


if __name__ == "__main__":
    main()
```

@angelayi My use case is something like this...
(Say _fused_quantize_dequantize is a highly optimized custom triton kernel)
```py
def quantize_dequantize(input: torch.Tensor, scale: float, zero_point: int, qmin: int, qmax: int):
    match (qmin, qmax):
        case (0, 255):
            dtype = torch.uint8
        case (-128, 127):
            dtype = torch.int8
        case _:
            raise ValueError(f"Unsupported quantization range: [{qmin}, {qmax}]")

    if torch.compiler.is_exporting():
        # During torch.export, represent quantize-dequantize as two separate nodes.
        # This is also standard representation in ExecuTorch
        input_q = torch.ops.quantized_decomposed.quantize_per_tensor(
            input, scale, zero_point, qmin, qmax, dtype,
        )
        return torch.ops.quantized_decomposed.dequantize_per_tensor(
            input_q, scale, zero_point, qmin, qmax, dtype,
        )

    # Ohterwise, use fast fused impl
    return _fused_quantize_dequantize(
        input, scale, zero_point, qmin, qmax, dtype
    )
```

@cyh2004 thanks for reporting! I claude-drafted the PR. 

> In some cases I want to create groups in which group rank does not follow the same order with global rank

is there some real advantage of not sorting? like perf, or something you cannot achieve without turning off sort

The precision loss occurs because the padding parameter is strictly typed as float in the ATen dispatcher definition (mapping to C++ double), leading to irreversible mantissa truncation for 64-bit integers exceeding 53 bits  before being passed to the tensor fill operation.
```YAML
// Fix in aten/src/ATen/native/native_functions.yaml
- func: to_padded_tensor(Tensor self, float padding, int[]? output_size=None) -> Tensor
+ func: to_padded_tensor(Tensor self, Scalar padding, int[]? output_size=None) -> Tensor
