```python
import torch
import torch.onnx


class ExactSampling1DKernel:
    input_names = ["ref_samples"]
    output_names = ["samples"]

    @staticmethod
    def forward(ref_samples, dtype):
        return ref_samples.to(dtype=dtype)

    @staticmethod
    def example_inputs(dtype):
        return (torch.tensor([-0.5, 0.0, 0.5], dtype=dtype),)


class FuncModule(torch.nn.Module):
    def __init__(self, func):
        super().__init__()
        self.func = func

    def forward(self, *args):
        return self.func(*args)


def export_onnx_dynamo(model_path: str, kernel, dtype) -> None:
    def forward_with_bound_dtype(*args):
        return kernel.forward(*args, dtype=dtype)

    onnx_program = torch.onnx.export(
        FuncModule(forward_with_bound_dtype),
        kernel.example_inputs(dtype),
        input_names=kernel.input_names,
        output_names=kernel.output_names,
        opset_version=18,
        dynamo=True,
    )

    onnx_program.save(model_path)


def export_onnx_legacy(model_path: str, kernel, dtype):
    def forward_with_bound_dtype(*args):
        return kernel.forward(*args, dtype=dtype)

    torch.onnx.export(
        FuncModule(forward_with_bound_dtype),
        kernel.example_inputs(dtype),
        input_names=kernel.input_names,
        output_names=kernel.output_names,
        f=model_path,
        opset_version=18,
        dynamo=False,
    )


export_onnx_legacy("trivial-legacy.onnx", ExactSampling1DKernel(), torch.float64)
export_onnx_dynamo("trivial-dynamo.onnx", ExactSampling1DKernel(), torch.float64)

```

found the bug c++ and python functions do not match 
```
template <typename T>
inline bool is_channels_last_strides_2d_s4(
    const ArrayRef<T> sizes,
    const ArrayRef<T> strides) {
  T min = 0;
  // special case for trivial C dimension. default to NCHW
  if (strides[1] == 0) {
    return false;
  }
  // loop strides indices
  for (auto& d : {1, 3, 2, 0}) {
    if (sizes[d] == 0) {
      return false;
    }
    if (strides[d] < min) {
      return false;
    }
    // Fallback to NCHW as default layout for ambiguous cases
    // This is the flaw of implicit memory_format from strides.
    // N111 tensor with identical strides for size 1 dimension;
    // Two cases could lead us here:
    // a. N111 contiguous Tensor ([N,1,1,1]@[1,1,1,1])
    // b. N11W contiguous Tensor sliced on the W-dimension.
    // ([N,1,1,1]@[W,W,W,W])
    if (d == 0 && min == strides[1]) {
      return false;
    }
    // This is necessary to:
    // 1. distinguish the memory_format of N1H1;
    //     [H, 1, 1, 1] channels_last stride
    //     [H, H, 1, 1] contiguous stride
    // 2. permutation of 1C1W:
    //     [1, C, 1, H]@[HC, H, H, 1] transpose(1, 3)
    //     [1, H, 1, C]@[HC, 1, H, H] shouldn't be identified as channels_last
    min = strides[d];
    if (sizes[d] > 1) {      
      min *= sizes[d];
    }
  }
  return true;
}
```
even before guard_or changes they ddi not match
```
# This combines is_channels_last_strides_2d and is_channels_last_strides_3d in
# c10/core/MemoryFormat.h into one function
def are_strides_like_channels_last(
    shape: Sequence[int], strides: Sequence[int]
) -> bool:
    from torch.fx.experimental.symbolic_shapes import guard_size_oblivious

    ndim = len(shape)

    if ndim == 4:
        # Check for channels_last_2d
        dim_order = [1, 3, 2, 0]
    elif ndim == 5:
        # Check for channels_last_3d
        dim_order = [1, 4, 3, 2, 0]
    else:
        return False

    if guard_size_oblivious(strides[1] == 0):
        return False

    min = 0
    for d in dim_order:
        if guard_size_oblivious(shape[d] == 0):
            return False
        if guard_size_oblivious(strides[d] < min):
            return False
        if d == 0 and min == strides[1]:
            return False
        min = strides[d]
        if guard_size_oblivious(strides[d] > 1):
            min *= shape[d]
    return True


def suggest_memory_format(x: TensorLikeType) -> torch.memory_format:
    if x.layout != torch.strided:
        return torch.contiguous_format

    if are_strides_like_channels_last(x.shape, x.stride()):
        return torch.channels_last if x.ndim == 4 else torch.channels_last_3d

    return torch.contiguous_format
```
